mapper.select:
SELECT COUNT(*)
FROM(
SELECT * , IFNULL(B.DDM_STATUS,'미개통') as status

)D
WHERE status = #{value}
AND DPP_STATUS = 'Y'

	AND D.DPP_ADMIN = #{UI_KEYNO}

SELECT *
WHERE 1=1 AND DPP_STATUS = 'Y'
AND C.DPP_KEYNO = #{type}
AND C.DPP_AREA = #{region}
AND B.DDM_STATUS = '정상' AND B.DDM_STATUS = '장애' AND B.DDM_STATUS = '연결 끊김' AND B.DDM_STATUS = '대기' AND B.DDM_STATUS IS NULL
AND DPP_USER = #{UI_KEYNO}
ORDER BY DPP_DATE ASC

SELECT SUM(B.DDM_ACTIVE_P) AS ACTIVE , SUM(B.DDM_D_DATA) AS DALIY, SUM(B.DDM_P_DATA) AS PREDATA , SUM(C.DPP_VOLUM) AS VOLUM, SUM(B.DDM_CUL_DATA) AS CUMULATIVE
WHERE 1=1
AND C.DPP_ADMIN = #{UI_KEYNO}

SELECT IFNULL(SUM(B.Cumulative_Generation),0) AS DATA FROM( SELECT A.* FROM ( SELECT * FROM dy_inverter_data WHERE DP_KEYNO = #{type}
AND Conn_date >= DATE_FORMAT(DATE_SUB(NOW(),INTERVAL 1 MONTH),'%Y-%m-01') AND Conn_date < DATE_FORMAT(NOW(),'%Y-%m-01') ORDER BY Conn_date DESC LIMIT 2000
AND Conn_date >= DATE_FORMAT(NOW(),'%Y-%m-01') AND Conn_date < DATE_ADD(DATE_FORMAT(NOW(),'%Y-%m-01'), INTERVAL 1 MONTH) ORDER BY Conn_date DESC LIMIT 2000
AND YEAR(Conn_date) = YEAR(NOW())
)A GROUP BY A.DI_NAME )B

SELECT MIN(Conn_date) as mind , MAX(Conn_date) as maxd
FROM dy_inverter_data
WHERE DP_KEYNO = #{type}
AND DI_NAME = #{name}
AND
DATE(Conn_date) = CURDATE()

SELECT *
FROM dy_inverter_data
WHERE DP_KEYNO = #{type}
AND DI_NAME = #{name}
AND Conn_date = #{date}

SELECT * FROM( SELECT * FROM dy_inverter_data WHERE DP_KEYNO = #{type}
AND DATE(Conn_date) >= #{searchBeginDate}
AND DATE(Conn_date) <= #{searchEndDate}
ORDER BY Conn_date DESC LIMIT 2000 )A WHERE 1=1
AND A.DI_NAME = '인버터 ${InverterType}호'
GROUP BY A.DI_NAME ORDER BY A.Conn_date ASC

SELECT AA.DI_NAME, C.YMDHM AS time_slot, IFNULL(ROUND(MAX(AA.Active_Power), 2), 0) AS power FROM ( SELECT DP_KEYNO, DI_NAME, Active_Power, CASE WHEN MINUTE(Conn_date) >= 0 AND MINUTE(Conn_date) < 30 THEN CONCAT(DATE_FORMAT(Conn_date, '%H'), ':00') WHEN MINUTE(Conn_date) >= 30 AND MINUTE(Conn_date) < 60 THEN CONCAT(DATE_FORMAT(Conn_date, '%H'), ':30') END AS hhmm FROM dy_inverter_data WHERE DP_KEYNO = ${type} AND Conn_date >= CURDATE() AND Conn_date < DATE_ADD(CURDATE(), INTERVAL 1 DAY) AND Active_Power > 0 LIMIT 10000 ) AA RIGHT JOIN ( WITH RECURSIVE A AS (
SELECT STR_TO_DATE(DATE_FORMAT(NOW(),'%Y%m%d06'),'%Y%m%d%H%') AS YMDHM UNION ALL SELECT DATE_ADD(A.YMDHM, INTERVAL 30 MINUTE) AS YMDHM FROM A WHERE A.YMDHM < STR_TO_DATE(DATE_FORMAT(NOW(),'%Y%m%d19'), '%Y%m%d%H')
) SELECT DATE_FORMAT(YMDHM, '%H:%i') AS YMDHM FROM A ) C ON AA.hhmm = C.YMDHM GROUP BY AA.DI_NAME, C.YMDHM ORDER BY AA.DI_NAME, C.YMDHM

SELECT * FROM( 
	SELECT * FROM( 
		SELECT * FROM dy_inverter_data_main 
		WHERE DDM_DPP_KEYNO = #{type} 

			 AND DATE(DDM_DATE) >= #{searchBeginDate}  


			 AND DATE(DDM_DATE) <= #{searchEndDate}  

		ORDER BY DDM_DATE DESC LIMIT 3000 
	)A 
	GROUP BY DATE(DDM_DATE) 
)B 
WHERE 1=1 
AND CAST(B.DDM_D_DATA as DECIMAL(10,6)) = ( 
	SELECT 
		 MIN(D.DDM_D_DATA)  
		 MAX(CAST(D.DDM_D_DATA as DECIMAL(10,6)))  
	FROM( 
		SELECT * FROM( 
			SELECT * FROM dy_inverter_data_main 
			WHERE DDM_DPP_KEYNO = #{type} 

				 AND DATE(DDM_DATE) >= #{searchBeginDate}  


				 AND DATE(DDM_DATE) <= #{searchEndDate}  

			ORDER BY DDM_DATE DESC LIMIT 1000 
		)C 
		GROUP BY DATE(DDM_DATE) 
	)D 
) 
LIMIT 1

SELECT * ,DATE(DDM_DATE) AS FORMATDATE FROM( SELECT * FROM( SELECT * FROM dy_inverter_data_main WHERE DDM_DPP_KEYNO = #{type}
AND DATE(DDM_DATE) >= #{searchBeginDate}
AND DATE(DDM_DATE) <= #{searchEndDate}
ORDER BY DDM_DATE DESC LIMIT 100000 )A GROUP BY DATE(DDM_DATE) ORDER BY DDM_DATE DESC )B LEFT JOIN dy_power_plant C ON B.DDM_DPP_KEYNO = C.DPP_KEYNO

choose.when:
SELECT Conn_date as ddtt, Cumulative_Generation as DDM_CUL_DATA, 0 as sdata FROM dy_inverter_data WHERE DP_KEYNO = #{type}
AND DATE(Conn_date) = CURDATE()
ORDER BY Conn_date ASC LIMIT 2000

choose.otherwise:
SELECT A.DDM_DATE as ddtt, A.DDM_CUL_DATA , A.DDM_CUL_DATA - B.PREVIOUS_D_DATA AS sdata FROM ( SELECT DATE_FORMAT(AA.DDM_DATE,'%Y-%m-%d') as DDM_DATE , AA.DDM_CUL_DATA FROM( SELECT DM.DDM_DATE , DM.DDM_CUL_DATA FROM dy_inverter_data_main DM INNER JOIN ( SELECT DDM_DPP_KEYNO, DATE(DDM_DATE) as DDM_DAY, MAX(DDM_DATE) AS MaxDate FROM dy_inverter_data_main WHERE DDM_DPP_KEYNO = #{type}
AND DATE(DDM_DATE) >= #{searchBeginDate} AND DATE(DDM_DATE) <= #{searchEndDate}
GROUP BY DDM_DPP_KEYNO, DATE(DDM_DATE) ) MD ON DM.DDM_DPP_KEYNO = MD.DDM_DPP_KEYNO AND DM.DDM_DATE = MD.MaxDate ORDER BY DM.DDM_DATE DESC LIMIT 10000 )AA GROUP BY
DATE_FORMAT(DDM_DATE,'%Y-%m') DATE(DDM_DATE)
ORDER BY DDM_DATE desc ) A JOIN ( SELECT DATE_FORMAT(BB.DDM_DATE,'%Y-%m-%d') as DDM_DATE , BB.PREVIOUS_D_DATA FROM( select DDM_DATE , DDM_CUL_DATA as PREVIOUS_D_DATA FROM dy_inverter_data_main WHERE DDM_DPP_KEYNO = #{type}
AND DATE(DDM_DATE) >= DATE_SUB(#{searchBeginDate}, INTERVAL 1 MONTH) AND DATE(DDM_DATE) <= #{searchEndDate}
ORDER BY DDM_DATE DESC LIMIT 10000 )BB GROUP BY
DATE_FORMAT(DDM_DATE,'%Y-%m') DATE(DDM_DATE)
ORDER BY DDM_DATE desc ) B ON
DATE_FORMAT(A.DDM_DATE,'%Y-%m') = DATE_FORMAT(DATE_ADD( DATE_FORMAT(B.DDM_DATE,'%Y-%m-%d'), INTERVAL 1 MONTH),'%Y-%m') DATE_FORMAT(A.DDM_DATE,'%Y-%m-%d') = DATE_ADD( DATE_FORMAT(B.DDM_DATE,'%Y-%m-%d'), INTERVAL 1 DAY)
GROUP BY DATE_FORMAT(A.DDM_DATE, '%Y-%m-%d') ORDER BY A.DDM_DATE DESC

