mapper.select:
SELECT IFNULL(SUM(A.Cumulative_Generation), 0) FROM ( SELECT DI_NAME, MAX(Conn_date) AS MaxConnDate FROM dy_inverter_data WHERE DP_KEYNO = #{type}
AND YEAR(Conn_date) = #{Conn_date}
AND Conn_date >= CONCAT(#{Conn_date}, '-01 00:00:00') AND Conn_date < DATE_ADD(CONCAT(#{Conn_date}, '-01 00:00:00'), INTERVAL 1 MONTH)
GROUP BY DI_NAME ) AS B JOIN dy_inverter_data A ON A.DI_NAME = B.DI_NAME AND A.Conn_date = B.MaxConnDate WHERE DP_KEYNO = #{type}

SELECT IFNULL(SUM(A.Cumulative_Generation), 0) FROM ( SELECT DI_NAME, MAX(Conn_date) AS MaxConnDate FROM dy_inverter_data WHERE DP_KEYNO = #{type} AND ( DI_NAME LIKE '%인버터 1%' OR DI_NAME LIKE '%인버터 2%' OR DI_NAME LIKE '%1번%' OR DI_NAME LIKE '%2번%' )
AND YEAR(Conn_date) = #{Conn_date}
AND Conn_date >= CONCAT(#{Conn_date}, '-01 00:00:00') AND Conn_date < DATE_ADD(CONCAT(#{Conn_date}, '-01 00:00:00'), INTERVAL 1 MONTH)
GROUP BY DI_NAME ) AS B JOIN dy_inverter_data A ON A.DI_NAME = B.DI_NAME AND A.Conn_date = B.MaxConnDate WHERE A.DP_KEYNO = #{type}

SELECT IFNULL(MAX(A.DDM_CUL_DATA), 0) FROM ( SELECT DDM_DPP_KEYNO, MAX(DDM_DATE) AS MaxDate FROM dy_inverter_data_main WHERE DDM_DPP_KEYNO = #{type}
AND YEAR(DDM_DATE) = #{Conn_date}
AND DDM_DATE >= CONCAT(#{Conn_date}, '-01 00:00:00') AND DDM_DATE < DATE_ADD(CONCAT(#{Conn_date}, '-01 00:00:00'), INTERVAL 1 MONTH)
GROUP BY DDM_DPP_KEYNO ) AS B JOIN dy_inverter_data_main A ON A.DDM_DPP_KEYNO = B.DDM_DPP_KEYNO AND A.DDM_DATE = B.MaxDate WHERE A.DDM_DPP_KEYNO = #{type}

SELECT *

WHERE 1=1
AND DPP_STATUS = 'Y'

	AND C.DPP_KEYNO = #{type}


	AND C.DPP_AREA = #{region}



		AND B.DDM_STATUS = '정상'
		AND B.DDM_STATUS = '장애'
		AND B.DDM_STATUS IS NULL



	AND DPP_ADMIN = #{UI_KEYNO}

ORDER BY DPP_DATE ASC

