mapper.select:
SELECT g.kpd_Date, ROUND(g.발전량_kWh - IFNULL(e.잉여전력_kWh, 0), 3) AS a4, IFNULL(e.잉여전력_kWh, 0) AS a5 FROM ( /* 발전량(kWh): 일 마지막 누적 - 전일 마지막 누적 */ SELECT ymd AS kpd_Date, ROUND(gen_end - LAG(gen_end) OVER (ORDER BY ymd), 3) AS 발전량_kWh FROM ( SELECT ymd, MAX(gen_kwh) AS gen_end FROM ( /* 과거 */ SELECT DATE(STR_TO_DATE(Conn_date, '%Y-%m-%d %H:%i:%s')) AS ymd, CAST(Cumulative_Generation AS DECIMAL(18,3)) AS gen_kwh FROM monitering.dy_detail_data WHERE DP_KEYNO = '63' AND Conn_date IS NOT NULL AND Cumulative_Generation IS NOT NULL AND STR_TO_DATE(Conn_date, '%Y-%m-%d %H:%i:%s') >= DATE_SUB(CURDATE(), INTERVAL 10 DAY)
UNION ALL
/* 오늘 */ SELECT DATE(Conn_date) AS ymd, CAST(Cumulative_Generation AS DECIMAL(18,3)) AS gen_kwh FROM monitering.dy_inverter_data WHERE DP_KEYNO = '63' AND Conn_date IS NOT NULL AND Cumulative_Generation IS NOT NULL AND Conn_date >= CURDATE() ) u GROUP BY ymd ) d ) g LEFT JOIN ( /* 잉여전력(kWh): 음수 W만 → (-W)*60/3600*0.001 */ SELECT DATE(kpd_conn) AS kpd_Date, ROUND( SUM( CASE WHEN CAST(kpd_data4 AS SIGNED) < 0 THEN (-CAST(kpd_data4 AS SIGNED)) * 60 / 3600 * 0.001 ELSE 0 END ) , 3) AS 잉여전력_kWh FROM monitering.korea_pospump_data WHERE kpd_conn >= DATE_SUB(CURDATE(), INTERVAL 10 DAY) AND kpd_conn IS NOT NULL AND kpd_data4 IS NOT NULL GROUP BY DATE(kpd_conn) ) e ON e.kpd_Date = g.kpd_Date WHERE g.kpd_Date >= DATE_SUB(CURDATE(), INTERVAL 5 DAY) ORDER BY g.kpd_Date DESC LIMIT 5
